# tco/model.py
from dataclasses import dataclass, field

@dataclass
class TCOComponent:
    name:        str
    year1:       float   # USD
    year2:       float
    year3:       float
    notes:       str = ""

    @property
    def total(self) -> float:
        return self.year1 + self.year2 + self.year3

@dataclass
class TCOScenario:
    name:        str              # "Build" | "Buy" | "Partner"
    components:  list[TCOComponent] = field(default_factory=list)

    @property
    def total(self) -> float:
        return sum(c.total for c in self.components)

    def year_total(self, year: int) -> float:
        return sum(getattr(c, f"year{year}") for c in self.components)

    def summary(self) -> dict:
        return {
            "scenario":  self.name,
            "year1":     self.year_total(1),
            "year2":     self.year_total(2),
            "year3":     self.year_total(3),
            "3yr_total": self.total,
            "breakdown": [
                {"component": c.name, "total": c.total, "notes": c.notes}
                for c in self.components
            ],
        }
